// Sinatura hace POST a esta URL tras cada firma (modelo push). Aún no está documentado
// el shape exacto del body, así que extraemos el identificador del trabajo de firma — el
// mismo valor que guardamos en firma.sinatura_id (newSignatureJob de la respuesta create) —
// probando las claves más probables. Tras el primer Ping/evento real, mira el output de
// este nodo (_raw) y deja SOLO la clave correcta para que quede explícito.
const b = $json.body || {};
const q = $json.query || {};
const sid =
  b.signatureJob ?? b.newSignatureJob ?? b.signatureJobId ?? b.signature_job ??
  b.jobId ?? b.job ?? b.id ?? q.signatureJob ?? q.id ?? null;
return [{ json: { sinatura_id: sid != null ? String(sid) : null, _raw: b } }];

parameters.query:
-- Mapea la notificación de Sinatura a NUESTRO documento por el id del trabajo de firma.
-- Si no hay coincidencia (p. ej. el Ping de prueba), devuelve 0 filas y el flujo no hace nada.
SELECT id_documento FROM firma WHERE sinatura_id = $1;

parameters.jsCode:
// Si encontramos la firma, delegamos en la acción sincronizarFirma del Motor Firmas
// (que ya consulta el estado en Sinatura, descarga el PDF firmado y actualiza la BD).
// Reutilizamos esa lógica en vez de duplicarla: una sola fuente de verdad para el mapeo
// de estados. Si no hay coincidencia (Ping de prueba o sinatura_id desconocido), no hacemos
// nada (return []), pero el webhook ya respondió 200 a Sinatura por el responseMode.
const r = $json || {};
if (r.id_documento == null || r.id_documento === '') {
  return [];
}
return [{ json: { body: { action: 'sincronizarFirma', firmaData: { doc_id: r.id_documento } } } }];
